import Animated, {FadeIn, FadeOut, Layout} from 'react-native-reanimated';
export function InlineSearchHeader({title, onSearch}: {title: string; onSearch: (q: string) => void}) { const [searching, setSearching] = useState(false); const [q, setQ] = useState(''); const ref = useRef<TextInput>(null); return (<Animated.View layout={Layout.springify()} style={s.header}>{searching ? (<Animated.View entering={FadeIn} style={s.searchRow}><TextInput ref={ref} autoFocus value={q} onChangeText={(v) => { setQ(v); onSearch(v); }} placeholder='Search' placeholderTextColor='#8E8E93' style={s.input}/><Pressable onPress={() => { setSearching(false); setQ(''); onSearch(''); }}><Text style={s.cancel}>Cancel</Text></Pressable></Animated.View>) : (<Animated.View entering={FadeIn} style={s.titleRow}><Text style={s.title}>{title}</Text><Pressable onPress={() => setSearching(true)}><Text style={s.icon}>{'⌕'}</Text></Pressable></Animated.View>)}</Animated.View>); }
