// Snackbar.tsx
import React, {useEffect} from 'react';
import {StyleSheet, View, Text, Pressable, Platform} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, withTiming, runOnJS} from 'react-native-reanimated';
import {useSafeAreaInsets} from 'react-native-safe-area-context';
export function Snackbar({message, actionLabel, onAction, onDismiss}: {message: string; actionLabel?: string; onAction?: () => void; onDismiss: () => void}) { const insets = useSafeAreaInsets(); const y = useSharedValue(100); useEffect(() => { y.value = withSpring(0, {damping: 22, stiffness: 240}); const t = setTimeout(() => { y.value = withTiming(100, {duration: 200}, () => runOnJS(onDismiss)()); }, 5000); return () => clearTimeout(t); }, []); const style = useAnimatedStyle(() => ({transform: [{translateY: y.value}]})); return (<Animated.View style={[s.snack, {bottom: insets.bottom + 80}, style]}><Text style={s.msg}>{message}</Text>{actionLabel && <Pressable onPress={onAction}><Text style={s.action}>{actionLabel}</Text></Pressable>}</Animated.View>); }
const s = StyleSheet.create({snack:{position:'absolute', left:16, right:16, padding:14, backgroundColor:'#2C2C2E', borderRadius:8, flexDirection:'row', alignItems:'center', justifyContent:'space-between', ...Platform.select({ios:{shadowColor:'#000', shadowOpacity:0.3, shadowRadius:12}, android:{elevation:6}})}, msg:{color:'#fff', flex:1}, action:{color:'#0A84FF', fontWeight:'600', textTransform:'uppercase', fontSize:13}});

