import {useEffect, useRef} from 'react';
import {AccessibilityInfo} from 'react-native';
export function useAnnounceNewMessage(messages: any[]) { const prevLen = useRef(messages.length); useEffect(() => { if (messages.length > prevLen.current) { const last = messages[messages.length - 1]; AccessibilityInfo.announceForAccessibility(`New message from ${last.from}: ${last.text}`); } prevLen.current = messages.length; }, [messages.length]); }

