import React, {useState, useEffect} from 'react';
import {StyleSheet, View, TextInput, ActivityIndicator, Text} from 'react-native';
export function ValidatingField({value, onChange, validate}: {value: string; onChange: (v: string) => void; validate: (v: string) => Promise<boolean>}) { const [state, setState] = useState<'idle'|'checking'|'ok'|'err'>('idle'); useEffect(() => { if (!value) { setState('idle'); return; } setState('checking'); const t = setTimeout(async () => { const ok = await validate(value); setState(ok ? 'ok' : 'err'); }, 400); return () => clearTimeout(t); }, [value]); return (<View style={s.row}><TextInput value={value} onChangeText={onChange} placeholder='Username' placeholderTextColor='#8E8E93' autoCapitalize='none' style={s.input}/>{state === 'checking' && <ActivityIndicator/>}{state === 'ok' && <Text style={s.ok}>{'✓'}</Text>}{state === 'err' && <Text style={s.err}>{'✗'}</Text>}</View>); }
const s = StyleSheet.create({row:{flexDirection:'row', alignItems:'center', gap:8, padding:8, backgroundColor:'#1C1C1E', borderRadius:10, paddingHorizontal:14, height:44}, input:{flex:1, color:'#fff', fontSize:16}, ok:{color:'#30D158', fontSize:18}, err:{color:'#FF453A', fontSize:18}});

